        val uri = java.net.URI.create("$baseUrl/fixtures/uuid_field_invalid_format/items/")
        val builder = java.net.http.HttpRequest.newBuilder(uri)
            .method("POST", java.net.http.HttpRequest.BodyPublishers.ofString("{\"item_id\":\"not-a-valid-uuid\",\"name\":\"Item\"}"))
            .header("Content-Type", "application/json")
            .header("Content-Type", "application/json")
        val response = java.net.http.HttpClient.newHttpClient()
            .send(builder.build(), java.net.http.HttpResponse.BodyHandlers.ofString())
        assertEquals(422, response.statusCode(), "status code mismatch")
        val bodyJson = MAPPER.readTree(response.body())
        val expectedJson = MAPPER.readTree("{\"detail\":\"1 validation error in request\",\"errors\":[{\"input\":\"not-a-valid-uuid\",\"loc\":[\"body\",\"item_id\"],\"msg\":\"Input should be a valid UUID\",\"type\":\"uuid_parsing\"}],\"status\":422,\"title\":\"Request Validation Failed\",\"type\":\"https://spikard.dev/errors/validation-error\"}")
        assertEquals(expectedJson, bodyJson, "body mismatch")
    }

